export default function KarnatakaMap({ offices }: { offices: Office[] }) {
  const [hovered, setHovered] = useState<string | null>(null);
  const pathRefs = useRef<Record<string, SVGPathElement | null>>({});
  const [label, setLabel] = useState<{ x: number; y: number; text: string } | null>(null);

  const officeDistrictIds = new Set(
    offices.map((o) => CITY_TO_DISTRICT_ID[o.city]).filter(Boolean)
  );

  const districtIdToOffice = new Map(
    offices
      .filter((o) => CITY_TO_DISTRICT_ID[o.city])
      .map((o) => [CITY_TO_DISTRICT_ID[o.city], o])
  );

  function handleEnter(districtId: string) {
    setHovered(districtId);
    const el = pathRefs.current[districtId];
    if (el) {
      const bbox = el.getBBox();
      const office = districtIdToOffice.get(districtId);
      setLabel({
        x: bbox.x + bbox.width / 2,
        y: bbox.y + bbox.height / 2,
        text: office?.city ?? districtId,
      });
    }
  }

  function handleLeave() {
    setHovered(null);
    setLabel(null);
  }

  return (
    <div className="grid grid-cols-1 items-center gap-10 lg:grid-cols-[1.2fr_1fr]">
      <div className="relative mx-auto w-full max-w-md">
        <svg
          viewBox="0 0 455 711"
          className="w-full drop-shadow-sm"
          role="img"
          aria-label="Map of Karnataka showing our office locations"
        >
          {DISTRICTS.map((district) => {
            const isOfficeDistrict = officeDistrictIds.has(district.id);
            const isHovered = hovered === district.id;
            return (
              <path
                key={district.id}
                ref={(el) => {
                  pathRefs.current[district.id] = el;
                }}
                d={district.d}
                onMouseEnter={() => handleEnter(district.id)}
                onMouseLeave={handleLeave}
                style={{
                  fill: isHovered ? "#1d4ed8" : isOfficeDistrict ? "#2563eb" : "#e7ecf7",
                  stroke: "#94a3c4",
                  strokeWidth: 1,
                  cursor: isOfficeDistrict ? "pointer" : "default",
                  transition: "fill 0.15s ease",
                }}
              />
            );
          })}
        </svg>

        {label && (
          <div
            className="pointer-events-none absolute rounded bg-zinc-900 px-2 py-1 text-xs font-medium text-white"
            style={{
              left: `${(label.x / 455) * 100}%`,
              top: `${(label.y / 711) * 100}%`,
              transform: "translate(-50%, -130%)",
            }}
          >
            {label.text}
          </div>
        )}
      </div>

      <ul className="flex flex-wrap gap-x-8 gap-y-2 text-zinc-700">
        {offices.map((office) => {
          const districtId = CITY_TO_DISTRICT_ID[office.city];
          const isHighlighted = districtId !== undefined && hovered === districtId;
          return (
            <li
              key={office.id}
              className={`text-lg transition-colors ${
                isHighlighted ? "font-semibold text-blue-600" : ""
              } ${districtId ? "cursor-pointer" : ""}`}
              onMouseEnter={() => districtId && handleEnter(districtId)}
              onMouseLeave={handleLeave}
            >
              {office.city}
            </li>
          );
        })}
      </ul>
    </div>
  );
}